        long []dp=new long[n+1];
        Arrays.fill(dp,0l);
        dp[0]=1l;
        for(int i=1;i<=n;i++){
            dp[i]+=dp[i-1];
        }
        for(int i=2;i<=n;i++){
            dp[i]+=dp[i-2];
        }
        return dp[n];
    }
